import sys
from typing import List, Tuple

class TreeNode:
    def __init__(self, val: int):
        self.val = val
        self.left = None
        self.right = None

class Solution:
    def solve(self, root: TreeNode) -> Tuple[List[int], List[int], List[int]]:
        preorder, inorder, postorder = [], [], []
        if not root:
            return preorder, inorder, postorder
        stack = [(root, 0)]  # 0 = visit, 1 = left done, 2 = right done
        while stack:
            node, state = stack.pop()
            if state == 0:
                preorder.append(node.val)
                stack.append((node, 1))
                if node.left:
                    stack.append((node.left, 0))
            elif state == 1:
                inorder.append(node.val)
                stack.append((node, 2))
                if node.right:
                    stack.append((node.right, 0))
            else:
                postorder.append(node.val)
        return preorder, postorder, inorder

if __name__ == "__main__":
    data = sys.stdin.read().split()
    if not data:
        sys.exit(0)
    it = iter(data)
    n = int(next(it))
    values = [int(next(it)) for _ in range(n)]
    m = int(next(it))
    edges = [(int(next(it)), int(next(it))) for _ in range(m)]
    nodes = {val: TreeNode(val) for val in values}
    for p, c in edges:
        parent = nodes[p]
        child = nodes[c]
        if not parent.left:
            parent.left = child
        else:
            parent.right = child
    root = nodes[values[0]]
    sol = Solution()
    pre, post, ino = sol.solve(root)
    print(f"[{', '.join(map(str, pre))}] [{', '.join(map(str, post))}] [{', '.join(map(str, ino))}]")

