#include <numeric>
#include <bits/stdc++.h>
using namespace std;

struct TreeNode {
    int val;
    TreeNode *left, *right;
    TreeNode(int v) : val(v), left(nullptr), right(nullptr) {}
};

class Solution {
public:
    void solve(TreeNode* root) {
        vector<int> preorder, inorder, postorder;
        if (!root) {
            print(preorder, postorder, inorder);
            return;
        }
        vector<pair<TreeNode*, int>> st; // state 0,1,2
        st.emplace_back(root, 0);
        while (!st.empty()) {
            auto _tmp_binding_0 = st.back(); auto node = _tmp_binding_0.first; auto state = _tmp_binding_0.second;
            st.pop_back();
            if (state == 0) {
                preorder.push_back(node->val);
                st.emplace_back(node, 1);
                if (node->left) st.emplace_back(node->left, 0);
            } else if (state == 1) {
                inorder.push_back(node->val);
                st.emplace_back(node, 2);
                if (node->right) st.emplace_back(node->right, 0);
            } else {
                postorder.push_back(node->val);
            }
        }
        print(preorder, postorder, inorder);
    }
private:
    void print(const vector<int>& pre, const vector<int>& post, const vector<int>& ino) {
        auto vecToStr = [](const vector<int>& v){
            string s = "[";
            for (size_t i = 0; i < v.size(); ++i) {
                s += to_string(v[i]);
                if (i + 1 != v.size()) s += ", ";
            }
            s += "]";
            return s;
        };
        cout << vecToStr(pre) << " " << vecToStr(post) << " " << vecToStr(ino) << "\n";
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> vals(n);
    for (int i = 0; i < n; ++i) cin >> vals[i];
    int m; cin >> m;
    unordered_map<int, TreeNode*> nodes;
    for (int v : vals) nodes[v] = new TreeNode(v);
    for (int i = 0; i < m; ++i) {
        int p, c; cin >> p >> c;
        TreeNode* parent = nodes[p];
        TreeNode* child = nodes[c];
        if (!parent->left) parent->left = child;
        else parent->right = child;
    }
    TreeNode* root = nodes[vals[0]];
    Solution sol;
    sol.solve(root);
    return 0;
}
